mapper.select:
SELECT CATALOG_ID AS "catalogId", BUSINESS_CODE AS "businessCode", SERVICE_ID AS "serviceId", TRANSACTION_CODE AS "transactionCode", PROCESSING_TYPE AS "processingType", HANDLER_CLASS AS "handlerClass", AUTH_CODE AS "authCode", AUDIT_YN AS "auditYn", TIMEOUT_SEC AS "timeoutSec", USE_YN AS "useYn", DESCRIPTION AS "description" FROM OM_SERVICE_CATALOG WHERE 1 = 1
AND BUSINESS_CODE = #{businessCode}
AND SERVICE_ID LIKE '%' || #{serviceId} || '%'
AND USE_YN = #{useYn}
ORDER BY BUSINESS_CODE, SERVICE_ID

SELECT U.USER_ID AS "userId", U.USER_NAME AS "userName", U.BRANCH_ID AS "branchId",
       U.AUTH_GROUP_ID AS "authGroupId", G.AUTH_GROUP_NAME AS "authGroupName",
       U.USE_YN AS "useYn", U.LAST_LOGIN_TIME AS "lastLoginTime"
  FROM OM_USER U
  LEFT JOIN OM_AUTH_GROUP G ON U.AUTH_GROUP_ID = G.AUTH_GROUP_ID
 WHERE 1 = 1

    AND U.USER_ID = #{userId}


    AND U.BRANCH_ID = #{branchId}


    AND U.AUTH_GROUP_ID = #{authGroupId}

 ORDER BY U.USER_ID

SELECT MENU_ID AS "menuId", MENU_NAME AS "menuName", MENU_URL AS "menuUrl", PARENT_MENU_ID AS "parentMenuId", SORT_ORDER AS "sortOrder", USE_YN AS "useYn" FROM OM_MENU WHERE 1 = 1
AND USE_YN = #{useYn}
ORDER BY SORT_ORDER, MENU_ID

SELECT AUTH_GROUP_ID AS "authGroupId", AUTH_GROUP_NAME AS "authGroupName", DESCRIPTION AS "description", USE_YN AS "useYn" FROM OM_AUTH_GROUP WHERE 1 = 1
AND AUTH_GROUP_ID = #{authGroupId}
ORDER BY AUTH_GROUP_ID

SELECT ERROR_CODE AS "errorCode", ERROR_CATEGORY AS "errorCategory", USER_MESSAGE AS "userMessage", OPERATOR_MESSAGE AS "operatorMessage", ACTION_GUIDE AS "actionGuide", NOTIFY_TARGET AS "notifyTarget", USE_YN AS "useYn" FROM OM_ERROR_CODE WHERE 1 = 1
AND ERROR_CODE LIKE '%' || #{errorCode} || '%'
AND ERROR_CATEGORY = #{errorCategory}
AND USE_YN = #{useYn}
ORDER BY ERROR_CODE

SELECT JOB_ID AS "jobId", JOB_NAME AS "jobName", BUSINESS_CODE AS "businessCode", CRON_EXPR AS "cronExpr", USE_YN AS "useYn", DESCRIPTION AS "description" FROM OM_BATCH_JOB WHERE 1 = 1
AND BUSINESS_CODE = #{businessCode}
AND USE_YN = #{useYn}
ORDER BY JOB_ID

SELECT CONFIG_KEY AS "configKey", CONFIG_CATEGORY AS "configCategory", CONFIG_VALUE AS "configValue", EDITABLE_YN AS "editableYn", DESCRIPTION AS "description" FROM OM_SYSTEM_CONFIG WHERE 1 = 1
AND CONFIG_CATEGORY = #{configCategory}
ORDER BY CONFIG_CATEGORY, CONFIG_KEY

SELECT CODE_GROUP AS "codeGroup", CODE AS "code", CODE_NAME AS "codeName", SORT_ORDER AS "sortOrder", USE_YN AS "useYn", DESCRIPTION AS "description" FROM OM_COMMON_CODE WHERE 1 = 1
AND CODE_GROUP = #{codeGroup}
AND USE_YN = #{useYn}
ORDER BY CODE_GROUP, SORT_ORDER, CODE

SELECT F.AUTH_ID AS "authId", F.AUTH_GROUP_ID AS "authGroupId", G.AUTH_GROUP_NAME AS "authGroupName", F.MENU_ID AS "menuId", M.MENU_NAME AS "menuName", F.CAN_INQUIRY AS "canInquiry", F.CAN_REGISTER AS "canRegister", F.CAN_UPDATE AS "canUpdate", F.CAN_DELETE AS "canDelete", F.CAN_DOWNLOAD AS "canDownload" FROM OM_FUNCTION_AUTH F LEFT JOIN OM_AUTH_GROUP G ON F.AUTH_GROUP_ID = G.AUTH_GROUP_ID LEFT JOIN OM_MENU M ON F.MENU_ID = M.MENU_ID WHERE 1 = 1
AND F.AUTH_GROUP_ID = #{authGroupId}
ORDER BY F.AUTH_GROUP_ID, F.MENU_ID

SELECT D.AUTH_ID AS "authId", D.AUTH_GROUP_ID AS "authGroupId", G.AUTH_GROUP_NAME AS "authGroupName", D.BRANCH_SCOPE AS "branchScope", D.CUSTOMER_ACCESS_LEVEL AS "customerAccessLevel", D.DESCRIPTION AS "description" FROM OM_DATA_AUTH D LEFT JOIN OM_AUTH_GROUP G ON D.AUTH_GROUP_ID = G.AUTH_GROUP_ID WHERE 1 = 1
AND D.AUTH_GROUP_ID = #{authGroupId}
ORDER BY D.AUTH_GROUP_ID

mapper.delete:
DELETE FROM OM_CACHE_STATUS
 WHERE CACHE_NAME = #{cacheName}

    AND CACHE_KEY = #{cacheKey}
